make_combined <- function() {
  # grid::grid.draw() does not accept a `vp=` argument in some R/grid versions.
  # Draw each ggplot grob after explicitly pushing the target viewport.
  draw_in_layout <- function(plot_obj, row, col) {
    grid::pushViewport(grid::viewport(layout.pos.row = row, layout.pos.col = col))
    grid::grid.draw(ggplot2::ggplotGrob(plot_obj))
    grid::popViewport()
  }

  grid::grid.newpage()
  grid::pushViewport(grid::viewport(layout = grid::grid.layout(
    nrow = 2, ncol = 2,
    heights = grid::unit(c(0.52, 0.48), "npc"),
    widths = grid::unit(c(0.43, 0.57), "npc")
  )))
  on.exit(grid::popViewport(), add = TRUE)

  draw_in_layout(pA, row = 1, col = 1)
  draw_in_layout(pB, row = 1, col = 2)
  draw_in_layout(pC, row = 2, col = 1:2)
}

save_main_figure_pdf <- function(path) {
  grDevices::pdf(path, width = 13.2, height = 9.4, onefile = TRUE)
  on.exit(grDevices::dev.off(), add = TRUE)
  make_combined()
}

save_main_figure_png <- function(path) {
  grDevices::png(path, width = 3960, height = 2820, res = 300)
  on.exit(grDevices::dev.off(), add = TRUE)
  make_combined()
}

save_gg_pdf <- function(plot_obj, path, width, height) {
  grDevices::pdf(path, width = width, height = height, onefile = TRUE)
  on.exit(grDevices::dev.off(), add = TRUE)
  print(plot_obj)
}

save_gg_png <- function(plot_obj, path, width, height, res = 300) {
  grDevices::png(path, width = width, height = height, res = res)
  on.exit(grDevices::dev.off(), add = TRUE)
  print(plot_obj)
}

save_main_figure_pdf(fig_pdf)
